const trigger = $('Notion Trigger').first().json;
const blocks = $input.all();

const title = trigger.Name || 'Untitled';
const status = trigger['Done?'] || 'Not started';
const tags = Array.isArray(trigger.Tags) ? trigger.Tags : [];
const obs = trigger.Obs || '';
const url = trigger.URL || '';
const archive = trigger.Archive || false;
const createdTime = trigger['Created time'] || new Date().toISOString();
const notionId = trigger.id;

function blocksToMarkdown(blocks) {
  let md = '';
  for (const block of blocks) {
    const b = block.json || block;
    const type = b.type;
    if (!type) continue;
    const text = b.content || '';
    switch (type) {
      case 'paragraph': md += text + '\n\n'; break;
      case 'heading_1': md += '# ' + text + '\n\n'; break;
      case 'heading_2': md += '## ' + text + '\n\n'; break;
      case 'heading_3': md += '### ' + text + '\n\n'; break;
      case 'bulleted_list_item': md += '- ' + text + '\n'; break;
      case 'numbered_list_item': md += '1. ' + text + '\n'; break;
      case 'to_do':
        const checked = b.to_do?.checked ? 'x' : ' ';
        md += '- [' + checked + '] ' + text + '\n'; break;
      case 'quote': md += '> ' + text + '\n\n'; break;
      case 'code':
        const lang = b.code?.language || '';
        md += '```' + lang + '\n' + text + '\n```\n\n'; break;
      case 'divider': md += '---\n\n'; break;
      case 'bookmark':
        const bmUrl = b.bookmark?.url || '';
        md += '[' + bmUrl + '](' + bmUrl + ')\n\n'; break;
      case 'image':
        const imgUrl = b.image?.file?.url || b.image?.external?.url || '';
        if (imgUrl) md += '![](' + imgUrl + ')\n\n'; break;
      case 'callout':
        const icon = b.callout?.icon?.emoji || '';
        md += '> ' + icon + ' ' + text + '\n\n'; break;
      default: if (text) md += text + '\n\n';
    }
  }
  return md.trim();
}

const content = blocksToMarkdown(blocks);
const tagsYaml = tags.length > 0 ? '[' + tags.join(', ') + ']' : '[]';
const date = createdTime.split('T')[0];

let frontmatter = '---\n';
frontmatter += 'type: notion-sync\n';
frontmatter += 'source: notion\n';
frontmatter += 'notion_id: ' + notionId + '\n';
frontmatter += 'date: ' + date + '\n';
frontmatter += 'status: ' + status + '\n';
frontmatter += 'tags: ' + tagsYaml + '\n';
frontmatter += 'archive: ' + archive + '\n';
if (url) frontmatter += 'url: ' + url + '\n';
if (obs) frontmatter += 'obs: "' + obs.replace(/"/g, '\\"') + '"\n';
frontmatter += '---\n\n';

let fullMd = frontmatter;
if (obs) fullMd += '> ' + obs + '\n\n';
if (url) fullMd += '**URL:** [' + url + '](' + url + ')\n\n';
if (content) fullMd += content;

const safeTitle = title
  .replace(/[\\/:*?"<>|]/g, '-')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 100);

const vaultPath = '/Users/aryribeiromacmini/Library/Mobile Documents/iCloud~md~obsidian/Documents/AryVault/00-Inbox';
const filePath = vaultPath + '/' + safeTitle + '.md';

return [{ json: { filePath, content: fullMd, title, tags, obs, url, notionId } }];

const md = $('Convert to Markdown').first().json;
const title = md.title || 'Untitled';
const tags = (md.tags || []).join(', ');
const obs = md.obs || '';
const url = md.url || '';
const content = (md.content || '').substring(0, 5000);

const noteText = `Title: ${title}\nTags: ${tags}\nObs: ${obs}\nURL: ${url}\nContent: ${content}`;

const prompt = `Analisa esta nota do Notion e extrai memorias uteis para sessoes futuras.\n\nNota: ${noteText.replace(/"/g, '\\"').replace(/\n/g, '\\n')}\n\nRegras: So inclui informacao que seria util relembrar. Decisoes, erros, padroes, insights, factos importantes. Se nada relevante retorna []. Retorna APENAS um JSON array sem markdown sem backticks: [{"type": "Decision|Learning|Error|Insight|Pattern|Fact", "summary": "frase curta", "details": "contexto", "importance": 1-5, "tags": ["tag1"]}]`;

const body = {
  model: "claude-haiku-4-5-20251001",
  max_tokens: 1024,
  messages: [
    { role: "user", content: prompt }
  ]
};

return [{ json: { body: JSON.stringify(body), notionId: md.notionId, title: md.title } }];

const raw = $input.first().json;

if (!raw.content || !raw.content[0] || !raw.content[0].text) {
  return [];
}

const content = raw.content[0].text;
const notionId = $('Prepare Haiku Body').first().json.notionId;
const title = $('Prepare Haiku Body').first().json.title;

let memories = [];
try {
  let cleaned = content.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  }
  memories = JSON.parse(cleaned);
} catch(e) {
  return [];
}

if (!Array.isArray(memories) || memories.length === 0) {
  return [];
}

return memories.map(m => ({
  json: {
    source: 'notion-notes',
    project: 'Personal',
    type: m.type || 'Insight',
    summary: m.summary || '',
    details: (m.details || '') + ' [Notion: ' + title + ']',
    importance: m.importance || 3,
    tags: Array.isArray(m.tags) ? m.tags : [m.tags || '']
  }
}));

const mem = $('Parse Memories JSON').item.json;
const embedding = $json.data[0].embedding;
return [{ json: { ...mem, embedding } }];

const item = $input.first().json;
const body = JSON.stringify({
  query_embedding: item.embedding,
  similarity_threshold: 0.85,
  filter_project: item.project || null
});
return [{ json: { ...item, similarBody: body } }];

const similarResults = $input.first().json;
const prev = $('Merge Embedding').item.json;

const hasSimilar = Array.isArray(similarResults) && similarResults.length > 0 && similarResults[0]?.id;

if (hasSimilar) {
  return [{ json: { action: 'update', existingId: similarResults[0].id, similarity: similarResults[0].similarity, ...prev } }];
} else {
  return [{ json: { action: 'insert', ...prev } }];
}

